import sys
from collections import defaultdict

def main():
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = data[1]

    length = 3 ** N

    # Function to get majority of a 3-bit group
    def majority(group):
        return '1' if group.count('1') >= 2 else '0'

    # Precompute the positions at each level
    positions = []
    current_length = length
    while current_length > 1:
        positions.append(list(range(0, current_length, 3)))
        current_length //= 3

    # For the last level, we just have one value
    # We try to flip the final bit by adjusting the previous levels
    # We will use a recursive function to try all possible modifications

    results = set()
    target = '0' if majority(A) == '1' else '1'  # Target is the opposite of the initial result

    # Memoization cache for subproblems
    memo = {}

    def dfs(level, current_string):
        key = (level, tuple(current_string))
        if key in memo:
            return memo[key]

        if level == N:
            # Base case: only the final bit remains
            result = current_string[0]
            memo[key] = result
            return result

        next_positions = positions[level]
        new_string = []
        for i in range(len(next_positions)):
            group_start = next_positions[i][0]
            group_end = next_positions[i][2]
            group = current_string[group_start:group_end+1]
            new_string.append(majority(group))

        res = dfs(level + 1, new_string)
        memo[key] = res
        return res

    # Find the minimal changes needed to achieve target
    def min_changes(target_str, original):
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def dp(pos, curr_str):
            if pos == len(original):
                return 0 if curr_str == target_str else float('inf')
            if curr_str[pos] == target_str[pos]:
                return dp(pos + 1, curr_str)
            else:
                return 1 + dp(pos + 1, curr_str)

        return dp(0, original)

    # Initial string
    initial = list(A)
    res = dfs(0, initial)
    if res == target:
        print(0)
    else:
        print(min_changes(target, A))

